 11→// --- Shared state ---
 12→
 13→static READY: AtomicBool = AtomicBool::new(false);
 14→static CURRENT_SERVER_ID: AtomicU64 = AtomicU64::new(0);
 15→static CURRENT_CHANNEL_ID: AtomicU64 = AtomicU64::new(0);
 16→
 17→fn current_server() -> Option<u64> {
 18→    let v = CURRENT_SERVER_ID.load(Ordering::Relaxed);
 19→    if v == 0 { None } else { Some(v) }
 20→}
 21→
 22→fn current_channel() -> Option<u64> {
 23→    let v = CURRENT_CHANNEL_ID.load(Ordering::Relaxed);
 24→    if v == 0 { None } else { Some(v) }
 25→}
 26→
 27→// --- Main ---
 28→
 29→fn main() {
 30→    let ctx = connect_to_db();
 31→    register_callbacks(&ctx);
 32→    subscribe_to_tables(&ctx);
 33→    ctx.run_threaded();
 34→    user_input_loop(&ctx);
 35→}
 36→
 37→// --- Connection ---
 38→
 39→fn connect_to_db() -> DbConnection {
 40→    let host = env::var("SPACETIMEDB_HOST").unwrap_or_else(|_| "https://maincloud.spacetimedb.com".to_string());
 41→    let db_name = env::var("SPACETIMEDB_DB_NAME").unwrap_or_else(|_| "spaces".to_string());
 42→
 43→    DbConnection::builder()
 44→        .on_connect(on_connected)
 45→        .on_connect_error(on_connect_error)
 46→        .on_disconnect(on_disconnected)
 47→        .with_token(creds_store().load().ok().flatten())
 48→        .with_database_name(db_name)
 49→        .with_uri(host)
 50→        .build()
 51→        .expect("Failed to connect")
 52→}
 53→
 54→fn creds_store() -> credentials::File {
 55→    credentials::File::new("spaces")
 56→}
 57→
 58→fn on_connected(_ctx: &DbConnection, identity: Identity, token: &str) {
 59→    if let Err(e) = creds_store().save(token) {
 60→        eprintln!("Failed to save credentials: {e:?}");
 61→    }
 62→    println!("Connected as: {}", identity.to_abbreviated_hex());
 63→}
 64→
 65→fn on_connect_error(_ctx: &ErrorContext, err: Error) {
 66→    eprintln!("Connection error: {err}");
 67→    std::process::exit(1);
 68→}
 69→
 70→fn on_disconnected(_ctx: &ErrorContext, err: Option<Error>) {
 71→    if let Some(err) = err {
 72→        eprintln!("Disconnected: {err}");
 73→        std::process::exit(1);
 74→    } else {
 75→        println!("Disconnected.");
 76→        std::process::exit(0);
 77→    }
 78→}
 79→
 80→// --- Callbacks ---
 81→
 82→fn register_callbacks(ctx: &DbConnection) {
 83→    ctx.db.user_profile().on_insert(on_user_profile_inserted);
 84→    ctx.db.user_presence().on_update(on_user_presence_updated);
 85→    ctx.db.message().on_insert(on_message_inserted);
 86→    ctx.db.server().on_insert(on_server_inserted);
 87→    ctx.db.channel().on_insert(on_channel_inserted);
 88→}
 89→
 90→fn on_user_profile_inserted(ctx: &EventContext, profile: &UserProfile) {
 91→    if matches!(ctx.event, Event::SubscribeApplied) {
 92→        return;
 93→    }
 94→    println!("[+] New user: {}", profile.username);
 95→}
 96→
 97→fn on_user_presence_updated(_ctx: &EventContext, old: &UserPresence, new: &UserPresence) {
 98→    let name = _ctx
 99→        .db
100→        .user_profile()
101→        .identity()
102→        .find(&new.identity)
103→        .map(|p| p.username.clone())
104→        .unwrap_or_else(|| "unknown".to_string());
105→    if !old.online && new.online {
106→        println!("[+] {} came online", name);
107→    } else if old.online && !new.online {
108→        println!("[-] {} went offline", name);
109→    }
110→}
111→
112→fn on_message_inserted(ctx: &EventContext, msg: &Message) {
113→    if matches!(ctx.event, Event::SubscribeApplied) {
114→        return;
115→    }
116→    // Only show messages for the current channel
117→    if let Some(ch_id) = current_channel() {
118→        if msg.channel_id == ch_id {
119→            print_message(ctx, msg);
120→        }
121→    }
122→}
123→
124→fn on_server_inserted(ctx: &EventContext, server: &Server) {
125→    if matches!(ctx.event, Event::SubscribeApplied) {
126→        return;
127→    }
128→    println!("[+] New server: {} (id={})", server.name, server.id);
129→}
130→
131→fn on_channel_inserted(ctx: &EventContext, channel: &Channel) {
132→    if matches!(ctx.event, Event::SubscribeApplied) {
133→        return;
134→    }
135→    println!("[+] New channel: #{} (id={})", channel.name, channel.id);
136→}
