138→// --- Helpers ---
139→
140→fn user_display_name(ctx: &impl RemoteDbContext, identity: &Identity) -> String {
141→    ctx.db()
142→        .user_profile()
143→        .identity()
144→        .find(identity)
145→        .map(|p| {
146→            p.display_name
147→                .clone()
148→                .unwrap_or_else(|| p.username.clone())
149→        })
150→        .unwrap_or_else(|| identity.to_abbreviated_hex().to_string())
151→}
152→
153→fn print_message(ctx: &impl RemoteDbContext, msg: &Message) {
154→    let sender = user_display_name(ctx, &msg.sender);
155→    let type_prefix = match msg.message_type {
156→        MessageType::System => "[SYSTEM] ",
157→        MessageType::Join => "[JOIN] ",
158→        MessageType::Leave => "[LEAVE] ",
159→        MessageType::AgentEvent => "[AGENT] ",
160→        MessageType::Text => "",
161→    };
162→    let thread_suffix = msg
163→        .thread_id
164→        .map(|t| format!(" (thread:{})", t))
165→        .unwrap_or_default();
166→    let reply_suffix = msg
167→        .reply_to_id
168→        .map(|r| format!(" (reply to:{})", r))
169→        .unwrap_or_default();
170→    let edit_mark = if msg.edited_at.is_some() { " (edited)" } else { "" };
171→    println!(
172→        "{}{}: {}{}{}{}",
173→        type_prefix, sender, msg.content, thread_suffix, reply_suffix, edit_mark
174→    );
175→}
