177→// --- Subscriptions ---
178→
179→fn subscribe_to_tables(ctx: &DbConnection) {
180→    ctx.subscription_builder()
181→        .on_applied(on_sub_applied)
182→        .on_error(on_sub_error)
183→        .subscribe_to_all_tables();
184→}
185→
186→fn on_sub_applied(ctx: &SubscriptionEventContext) {
187→    println!("\n=== Spaces - Discord Clone on SpacetimeDB ===\n");
188→
189→    // List servers
190→    let servers: Vec<_> = ctx.db.server().iter().collect();
191→    if servers.is_empty() {
192→        println!("No servers found.");
193→    } else {
194→        println!("Servers:");
195→        for s in &servers {
196→            println!("  [{}] {}", s.id, s.name);
197→        }
198→    }
199→
200→    // Auto-select first server
201→    if let Some(first) = servers.first() {
202→        CURRENT_SERVER_ID.store(first.id, Ordering::Relaxed);
203→        println!("\nActive server: {} (id={})", first.name, first.id);
204→
205→        // Show channels
206→        let channels: Vec<_> = ctx
207→            .db
208→            .channel()
209→            .iter()
210→            .filter(|c| c.server_id == first.id)
211→            .collect();
212→        if !channels.is_empty() {
213→            println!("Channels:");
214→            for ch in &channels {
215→                println!("  [{}] #{} ({:?})", ch.id, ch.name, ch.channel_type);
216→            }
217→            // Auto-select first text channel
218→            if let Some(text_ch) = channels.iter().find(|c| c.channel_type == ChannelType::Text) {
219→                CURRENT_CHANNEL_ID.store(text_ch.id, Ordering::Relaxed);
220→                println!("\nActive channel: #{} (id={})", text_ch.name, text_ch.id);
221→
222→                // Show recent messages
223→                let mut msgs: Vec<_> = ctx
224→                    .db
225→                    .message()
226→                    .iter()
227→                    .filter(|m| m.channel_id == text_ch.id && m.thread_id.is_none())
228→                    .collect();
229→                msgs.sort_by_key(|m| m.created_at);
230→                let recent: Vec<_> = msgs.iter().rev().take(25).collect::<Vec<_>>().into_iter().rev().collect();
231→                if !recent.is_empty() {
232→                    println!("\n--- Recent messages ---");
233→                    for msg in recent {
234→                        print_message(ctx, &msg);
235→                    }
236→                    println!("--- End ---\n");
237→                }
238→            }
239→        }
240→    }
241→
242→    println!("Type /help for commands, or type a message to send.");
243→    println!();
244→    READY.store(true, Ordering::Release);
245→}
246→
247→fn on_sub_error(_ctx: &ErrorContext, err: Error) {
248→    eprintln!("Subscription failed: {err}");
249→    std::process::exit(1);
250→}
