252→// --- User Input ---
253→
254→fn user_input_loop(ctx: &DbConnection) {
255→    // Wait for subscription to be applied before processing input
256→    while !READY.load(Ordering::Acquire) {
257→        std::thread::sleep(std::time::Duration::from_millis(50));
258→    }
259→    for line in std::io::stdin().lines() {
260→        let Ok(line) = line else {
261→            break;
262→        };
263→        let line = line.trim().to_string();
264→        if line.is_empty() {
265→            continue;
266→        }
267→
268→        if line.starts_with('/') {
269→            handle_command(ctx, &line);
270→        } else {
271→            // Send message to current channel
272→            if let Some(ch_id) = current_channel() {
273→                if let Err(e) = ctx.reducers.send_message(ch_id, line, None, None) {
274→                    eprintln!("Failed to send: {e}");
275→                }
276→            } else {
277→                eprintln!("No channel selected. Use /channel <id> to select one.");
278→            }
279→        }
280→    }
281→}
