283→fn handle_command(ctx: &DbConnection, input: &str) {
284→    let parts: Vec<&str> = input.splitn(2, ' ').collect();
285→    let cmd = parts[0];
286→    let arg = parts.get(1).map(|s| s.trim()).unwrap_or("");
287→
288→    match cmd {
289→        "/help" => print_help(),
290→        "/name" => cmd_set_name(ctx, arg),
291→        "/servers" => cmd_list_servers(ctx),
292→        "/server" => cmd_select_server(ctx, arg),
293→        "/join" => cmd_join_server(ctx, arg),
294→        "/leave" => cmd_leave_server(ctx, arg),
295→        "/create-server" => cmd_create_server(ctx, arg),
296→        "/channels" => cmd_list_channels(ctx),
297→        "/channel" => cmd_select_channel(ctx, arg),
298→        "/create-channel" => cmd_create_channel(ctx, arg),
299→        "/threads" => cmd_list_threads(ctx),
300→        "/thread" => cmd_create_thread(ctx, arg),
301→        "/members" => cmd_list_members(ctx),
302→        "/react" => cmd_react(ctx, arg),
303→        "/agent" => cmd_register_agent(ctx, arg),
304→        "/who" => cmd_who(ctx),
305→        "/history" => cmd_history(ctx, arg),
306→        _ => eprintln!("Unknown command: {cmd}. Type /help for available commands."),
307→    }
308→}
