373→fn cmd_select_server(ctx: &DbConnection, arg: &str) {
374→    if arg.is_empty() {
375→        eprintln!("Usage: /server <id>");
376→        return;
377→    }
378→
379→    // Try by ID first, then by name
380→    let server = if let Ok(id) = arg.parse::<u64>() {
381→        ctx.db.server().id().find(&id)
382→    } else {
383→        ctx.db.server().iter().find(|s| s.name.to_lowercase() == arg.to_lowercase())
384→    };
385→
386→    if let Some(s) = server {
387→        CURRENT_SERVER_ID.store(s.id, Ordering::Relaxed);
388→        CURRENT_CHANNEL_ID.store(0, Ordering::Relaxed);
389→        println!("Active server: {} (id={})", s.name, s.id);
390→
391→        // Show channels
392→        cmd_list_channels(ctx);
393→
394→        // Auto-select first text channel
395→        if let Some(ch) = ctx.db.channel().iter()
396→            .filter(|c| c.server_id == s.id && c.channel_type == ChannelType::Text)
397→            .next()
398→        {
399→            CURRENT_CHANNEL_ID.store(ch.id, Ordering::Relaxed);
400→            println!("Active channel: #{} (id={})", ch.name, ch.id);
401→        }
402→    } else {
403→        eprintln!("Server not found: {arg}");
404→    }
405→}
