 10→#[reducer]
 11→pub fn send_message(
 12→    ctx: &ReducerContext,
 13→    channel_id: u64,
 14→    content: String,
 15→    thread_id: Option<u64>,
 16→    reply_to_id: Option<u64>,
 17→) -> Result<(), String> {
 18→    if content.is_empty() {
 19→        return Err("Message content cannot be empty".to_string());
 20→    }
 21→    if content.len() > 4000 {
 22→        return Err("Message must be 4000 characters or fewer".to_string());
 23→    }
 24→
 25→    let (channel, _server) = auth::get_server_for_channel(ctx, channel_id)?;
 26→    auth::require_member(ctx, channel.server_id)?;
 27→
 28→    // Validate thread exists if specified
 29→    if let Some(tid) = thread_id {
 30→        let thread = ctx.db.thread().id().find(tid)
 31→            .ok_or("Thread not found")?;
 32→        if thread.archived {
 33→            return Err("Cannot post in an archived thread".to_string());
 34→        }
 35→        if thread.channel_id != channel_id {
 36→            return Err("Thread does not belong to this channel".to_string());
 37→        }
 38→        // Update thread's last_message_at
 39→        ctx.db.thread().id().update(Thread {
 40→            last_message_at: ctx.timestamp,
 41→            ..thread
 42→        });
 43→    }
 44→
 45→    // Validate reply target exists if specified
 46→    if let Some(rid) = reply_to_id {
 47→        ctx.db.message().id().find(rid)
 48→            .ok_or("Reply target message not found")?;
 49→    }
 50→
 51→    ctx.db.message().insert(Message {
 52→        id: 0,
 53→        channel_id,
 54→        thread_id,
 55→        sender: ctx.sender(),
 56→        content,
 57→        message_type: MessageType::Text,
 58→        created_at: ctx.timestamp,
 59→        edited_at: None,
 60→        reply_to_id,
 61→    });
 62→
 63→    Ok(())
 64→}
