 91→#[reducer]
 92→pub fn delete_message(ctx: &ReducerContext, message_id: u64) -> Result<(), String> {
 93→    let msg = ctx.db.message().id().find(message_id)
 94→        .ok_or("Message not found")?;
 95→
 96→    let is_sender = msg.sender == ctx.sender();
 97→
 98→    // Check if admin+ in the server
 99→    let (_channel, _server) = auth::get_server_for_channel(ctx, msg.channel_id)?;
100→    let is_admin = auth::get_member_role(ctx, _channel.server_id, ctx.sender())
101→        .map(|r| r.level() >= MemberRole::Admin.level())
102→        .unwrap_or(false);
103→
104→    if !is_sender && !is_admin {
105→        return Err("You can only delete your own messages, or be an admin".to_string());
106→    }
107→
108→    // Delete reactions first
109→    let reactions: Vec<_> = ctx.db.reaction().message_id().filter(&message_id).collect();
110→    for r in &reactions {
111→        ctx.db.reaction().id().delete(&r.id);
112→    }
113→
114→    ctx.db.message().id().delete(&message_id);
115→    Ok(())
116→}
